ini_set('display_errors', 1);
ini_set('display_startup_errors', 1);
error_reporting(E_ALL);

$root = __DIR__;
$results = [];

function add_result($item, $ok, $message = '') {
    global $results;
    $results[] = [$item, $ok, $message];
}

function ensure_dir($dir) {
    if (!is_dir($dir)) {
        mkdir($dir, 0755, true);
    }
}

function write_file_safe($relative, $contentB64) {
    global $root;
    $target = $root . DIRECTORY_SEPARATOR . str_replace('/', DIRECTORY_SEPARATOR, $relative);
    ensure_dir(dirname($target));

    $content = base64_decode($contentB64);

    if ($content === false) {
        add_result($relative, false, 'decode failed');
        return;
    }

    if (file_exists($target)) {
        @copy($target, $target . '.backup-' . date('Ymd-His'));
    }

    $ok = file_put_contents($target, $content) !== false;
    add_result($relative, $ok, $ok ? 'created/updated' : 'write failed');
}

function table_exists_install($pdo, $table) {
    try {
        $stmt = $pdo->prepare("SHOW TABLES LIKE ?");
        $stmt->execute([$table]);
        return (bool) $stmt->fetch();
    } catch (Throwable $e) {
        return false;
    }
}

function column_exists_install($pdo, $table, $column) {
    try {
        $stmt = $pdo->prepare("SHOW COLUMNS FROM `$table` LIKE ?");
        $stmt->execute([$column]);
        return (bool) $stmt->fetch();
    } catch (Throwable $e) {
        return false;
    }
}

function add_column_install($pdo, $table, $column, $sql) {
    if (column_exists_install($pdo, $table, $column)) {
        add_result("$table.$column", true, 'already exists');
        return true;
    }

    try {
        $pdo->exec($sql);
        add_result("$table.$column", true, 'added');
        return true;
    } catch (Throwable $e) {
        if (strpos($e->getMessage(), 'Duplicate column') !== false) {
            add_result("$table.$column", true, 'already exists / skipped');
            return true;
        }

        add_result("$table.$column", false, $e->getMessage());
        return false;
    }
}

$files = [
    'admin/users.php' => '',
];

foreach ($files as $relative => $contentB64) {
    write_file_safe($relative, $contentB64);
}

