            $insert = '<a class="<?= ($activeSidebar ?? '') === 'users' ? 'active' : ''; ?>" href="<?= e(BASE_URL); ?>admin/users.php"><i class="fa-solid fa-users"></i> Users</a>' . "\n";

            if (strpos($sidebar, '<a') !== false) {
                $sidebar = preg_replace('/(<a[^>]+>.*?Dashboard.*?<\/a>)/s', '$1' . "\n" . $insert, $sidebar, 1);
